async def test_in_loop():
    # Simulate _run_sync broken vs fixed
    def _run_sync_broken(coro):
        try:
            asyncio.get_running_loop()
        except RuntimeError:
            return asyncio.run(coro)
        # This path doesn't propagate context!
        from concurrent.futures import ThreadPoolExecutor
        pool = ThreadPoolExecutor(max_workers=1)
        return pool.submit(lambda: asyncio.run(coro)).result(timeout=5)

    def _run_sync_fixed(coro):
        try:
            asyncio.get_running_loop()
        except RuntimeError:
            return asyncio.run(coro)
        # Propagate context like _with_timeout does
        ctx = otel_context.get_current()
        from concurrent.futures import ThreadPoolExecutor
        pool = ThreadPoolExecutor(max_workers=1)
        def _run():
            token = otel_context.attach(ctx)
            try:
                return asyncio.run(coro)
            finally:
                otel_context.detach(token)
        return pool.submit(_run).result(timeout=5)

    result_broken = _run_sync_broken(check_baggage())
    print(f"Result with broken _run_sync (should be None): {result_broken}")

    result_fixed = _run_sync_fixed(check_baggage())
    print(f"Result with fixed _run_sync (should be 'test_value'): {result_fixed}")

